const { WebSocketServer } = require('ws');
const http = require('http');
const { v4: uuidv4 } = require('uuid');

const PORT = 8080;

// --- Game State ---
const gameState = {
    players: {}, // { playerId: { name: 'PlayerName', units: [], buildings: [] } }
    units: {},   // { unitId: { x, y, type, ownerId, hp, attackingId } }
    buildings: {}, // { buildingId: { x, y, type, ownerId, hp, productionQueue } }
    map: {
        width: 1000,
        height: 1000,
        resources: [ // Example static resources
            { id: 'res1', type: 'gold', x: 100, y: 100, amount: 5000 },
            { id: 'res2', type: 'wood', x: 800, y: 800, amount: 10000 }
        ]
    },
    lastUpdate: Date.now()
};

// --- Helper Functions ---
function generateId() {
    return uuidv4();
}

function broadcast(message) {
    wss.clients.forEach(client => {
        if (client.readyState === client.OPEN) {
            client.send(JSON.stringify(message));
        }
    });
}

function sendToPlayer(playerId, message) {
    const client = connectedClients[playerId];
    if (client && client.readyState === client.OPEN) {
        client.send(JSON.stringify(message));
    }
}

function initializePlayerBase(playerId, playerName) {
    const startingX = Math.random() * (gameState.map.width - 200) + 100;
    const startingY = Math.random() * (gameState.map.height - 200) + 100;

    // Create a starting building (e.g., Command Center)
    const commandCenterId = generateId();
    gameState.buildings[commandCenterId] = {
        id: commandCenterId,
        x: startingX,
        y: startingY,
        type: 'command_center',
        ownerId: playerId,
        hp: 1000,
        maxHp: 1000
    };

    // Create some starting units (e.g., Workers)
    for (let i = 0; i < 3; i++) {
        const workerId = generateId();
        gameState.units[workerId] = {
            id: workerId,
            x: startingX + 20 + i * 10,
            y: startingY + 20,
            type: 'worker',
            ownerId: playerId,
            hp: 100,
            maxHp: 100,
            speed: 2,
            targetX: null,
            targetY: null,
            targetEntityId: null
        };
        gameState.players[playerId].units.push(workerId);
    }
    gameState.players[playerId].buildings.push(commandCenterId);
}

// --- Command Processing ---
function processCommand(playerId, command) {
    console.log(`Processing command from ${playerId}:`, command);

    const player = gameState.players[playerId];
    if (!player) {
        console.warn(`Player ${playerId} not found.`);
        return;
    }

    switch (command.commandType) {
        case 'move':
            if (command.unitIds && (command.targetX !== undefined || command.targetY !== undefined)) {
                command.unitIds.forEach(unitId => {
                    const unit = gameState.units[unitId];
                    if (unit && unit.ownerId === playerId) {
                        unit.targetX = command.targetX;
                        unit.targetY = command.targetY;
                        unit.targetEntityId = null; // Clear attack/gather target
                    }
                });
            }
            break;

        case 'build':
            if (command.builderId && command.buildingType && command.x !== undefined && command.y !== undefined) {
                const builder = gameState.units[command.builderId];
                if (builder && builder.ownerId === playerId && builder.type === 'worker') {
                    const buildingId = generateId();
                    gameState.buildings[buildingId] = {
                        id: buildingId,
                        x: command.x,
                        y: command.y,
                        type: command.buildingType,
                        ownerId: playerId,
                        hp: 1, // Start with low HP, implies construction
                        maxHp: 500, // Example max HP
                        isUnderConstruction: true
                    };
                    gameState.players[playerId].buildings.push(buildingId);
                    // In a real game, the builder would move to the site and start building
                    // For now, just instant creation.
                }
            }
            break;

        case 'attack':
            if (command.attackerIds && command.targetEntityId) {
                const targetEntity = gameState.units[command.targetEntityId] || gameState.buildings[command.targetEntityId];
                if (targetEntity) {
                    command.attackerIds.forEach(attackerId => {
                        const attacker = gameState.units[attackerId];
                        if (attacker && attacker.ownerId === playerId) {
                            // Simple instant damage for demo. Real game would track movement, range, DPS.
                            // For demo, just assign target, damage will be simulated in a game loop.
                            attacker.targetEntityId = command.targetEntityId;
                        }
                    });
                }
            }
            break;

        // Add more command types as needed: gather, research, train, etc.
        case 'chat':
            if (command.message) {
                const chatMessage = {
                    type: 'chatMessage',
                    senderId: playerId,
                    senderName: player.name,
                    message: command.message,
                    timestamp: Date.now()
                };
                broadcast(chatMessage);
            }
            break;

        default:
            console.warn(`Unknown command type: ${command.commandType}`);
            break;
    }

    // After processing, send updated state to all clients
    sendGameStateUpdate();
}

function sendGameStateUpdate() {
    gameState.lastUpdate = Date.now();
    broadcast({
        type: 'gameStateUpdate',
        state: gameState // Sending full state for simplicity
    });
}

// --- WebSocket Server ---
const server = http.createServer();
const wss = new WebSocketServer({ server });

const connectedClients = {}; // Map playerId to WebSocket instance

wss.on('connection', ws => {
    const playerId = generateId();
    const playerName = `Player${Object.keys(gameState.players).length + 1}`;
    console.log(`Player ${playerName} (${playerId}) connected.`);

    connectedClients[playerId] = ws;

    gameState.players[playerId] = {
        id: playerId,
        name: playerName,
        color: `#${Math.floor(Math.random()*16777215).toString(16)}`, // Assign a random color
        units: [],
        buildings: []
    };

    initializePlayerBase(playerId, playerName);

    // Send initial setup data to the newly connected player
    sendToPlayer(playerId, {
        type: 'playerConnected',
        playerId: playerId,
        playerName: playerName,
        initialState: gameState // Send full current game state
    });

    // Notify all other players about the new player
    broadcast({
        type: 'playerJoined',
        playerId: playerId,
        playerName: playerName,
        color: gameState.players[playerId].color
    });

    // Send an immediate full game state update to everyone after the player is fully set up
    sendGameStateUpdate();

    ws.on('message', message => {
        try {
            const parsedMessage = JSON.parse(message.toString());
            if (parsedMessage.type === 'command') {
                processCommand(playerId, parsedMessage);
            } else {
                console.warn(`Unknown message type from ${playerId}: ${parsedMessage.type}`);
            }
        } catch (error) {
            console.error(`Failed to parse message from ${playerId}:`, error);
        }
    });

    ws.on('close', () => {
        console.log(`Player ${gameState.players[playerId].name} (${playerId}) disconnected.`);
        // Remove player's units and buildings from game state
        gameState.players[playerId].units.forEach(unitId => delete gameState.units[unitId]);
        gameState.players[playerId].buildings.forEach(buildingId => delete gameState.buildings[buildingId]);

        delete gameState.players[playerId];
        delete connectedClients[playerId];

        broadcast({
            type: 'playerLeft',
            playerId: playerId
        });

        sendGameStateUpdate();
    });

    ws.on('error', error => {
        console.error(`WebSocket error for player ${playerId}:`, error);
    });
});

// --- Simple Game Loop (for simulating unit movement, combat etc.) ---
let lastTickTime = Date.now();
const gameTickInterval = 1000 / 10; // 10 ticks per second

function gameLoop() {
    const now = Date.now();
    const deltaTime = (now - lastTickTime) / 1000; // time in seconds since last tick
    lastTickTime = now;

    let stateChanged = false;

    // Simulate unit movement
    for (const unitId in gameState.units) {
        const unit = gameState.units[unitId];
        if (unit.targetX !== null && unit.targetY !== null) {
            const dx = unit.targetX - unit.x;
            const dy = unit.targetY - unit.y;
            const distance = Math.sqrt(dx * dx + dy * dy);

            if (distance > unit.speed * deltaTime) { // If not yet at target
                unit.x += (dx / distance) * unit.speed * deltaTime;
                unit.y += (dy / distance) * unit.speed * deltaTime;
                stateChanged = true;
            } else { // Reached target
                unit.x = unit.targetX;
                unit.y = unit.targetY;
                unit.targetX = null;
                unit.targetY = null;
                stateChanged = true;
            }
        }
        // Simulate attack if targetEntityId is set
        if (unit.targetEntityId) {
            const target = gameState.units[unit.targetEntityId] || gameState.buildings[unit.targetEntityId];
            if (target) {
                // Simple damage application for demo
                // In a real game, check range, cooldowns, damage values
                const attackDamage = 5; // Example damage
                target.hp -= attackDamage;
                if (target.hp <= 0) {
                    console.log(`Entity ${target.id} destroyed.`);
                    if (gameState.units[target.id]) {
                        delete gameState.units[target.id];
                        // Also remove from player's unit list
                        for (const pId in gameState.players) {
                            gameState.players[pId].units = gameState.players[pId].units.filter(id => id !== target.id);
                        }
                    } else if (gameState.buildings[target.id]) {
                        delete gameState.buildings[target.id];
                        // Also remove from player's building list
                        for (const pId in gameState.players) {
                            gameState.players[pId].buildings = gameState.players[pId].buildings.filter(id => id !== target.id);
                        }
                    }
                    // Clear this unit's target since it's destroyed
                    unit.targetEntityId = null;
                }
                stateChanged = true;
            } else {
                // Target disappeared
                unit.targetEntityId = null;
                stateChanged = true;
            }
        }
    }

    // Simulate building construction
    for (const buildingId in gameState.buildings) {
        const building = gameState.buildings[buildingId];
        if (building.isUnderConstruction && building.hp < building.maxHp) {
            building.hp += 10; // Simple construction rate
            if (building.hp >= building.maxHp) {
                building.hp = building.maxHp;
                building.isUnderConstruction = false;
                console.log(`Building ${building.id} completed.`);
            }
            stateChanged = true;
        }
    }


    if (stateChanged) {
        sendGameStateUpdate();
    }
}

setInterval(gameLoop, gameTickInterval);


server.listen(PORT, () => {
    console.log(`WebSocket game server started on http://localhost:${PORT}`);
});